// Fetch Pinecone index stats and build namespace list
const PINECONE_HOST = '{{ $env.PINECONE_HOST }}';
const PINECONE_KEY = '{{ $env.PINECONE_API_KEY }}';

const resp = await fetch(`${PINECONE_HOST}/describe_index_stats`, {
  method: 'POST',
  headers: { 'Api-Key': PINECONE_KEY, 'Content-Type': 'application/json' },
  body: '{}',
});
if (!resp.ok) throw new Error(`describe_index_stats failed: ${resp.status}`);
const stats = await resp.json();

const namespaceMap = { 'gda-documents': 'gda-documents', '': 'ai-agent-attachments' };
const items = [];
for (const [ns, info] of Object.entries(stats.namespaces || {})) {
  const collection = namespaceMap[ns] !== undefined ? namespaceMap[ns] : ns;
  items.push({ json: { namespace: ns, collection, expected_count: info.vectorCount } });
}
return items;

// Backfill one Pinecone namespace → pgvector collection.
// VectorItem interface: { id, content, embedding, metadata }
// Backend reads document_id from metadata.document_id (NOT NULL in schema).
// Backend reads chunk_text from item.content.
const PINECONE_HOST = '{{ $env.PINECONE_HOST }}';
const PINECONE_KEY = '{{ $env.PINECONE_API_KEY }}';
const GDA_KEY = '{{ $env.GDA_WEBHOOK_KEY }}';
const BACKEND = 'http://gda-backend:3001';
const UPSERT_CHUNK = 10;

const { namespace: ns, collection, expected_count } = $input.first().json;
let fetched = 0, upserted = 0, batchNum = 0, token = null, errors = [];

function stripNull(s) { return typeof s === 'string' ? s.replace(/\0/g, '') : s; }

do {
  let url = `${PINECONE_HOST}/vectors/list?namespace=${encodeURIComponent(ns)}&limit=100`;
  if (token) url += `&paginationToken=${encodeURIComponent(token)}`;
  const listResp = await fetch(url, { headers: { 'Api-Key': PINECONE_KEY } });
  if (!listResp.ok) { errors.push(`list ${listResp.status}`); break; }
  const listData = await listResp.json();
  const ids = (listData.vectors || []).map(v => v.id);
  token = listData.pagination?.next || null;
  if (!ids.length) break;

  // Fetch vectors via GET with query params
  const params = ids.map(id => `ids=${encodeURIComponent(id)}`).join('&');
  const nsParam = ns ? `&namespace=${encodeURIComponent(ns)}` : '';
  const fetchResp = await fetch(`${PINECONE_HOST}/vectors/fetch?${params}${nsParam}`, {
    headers: { 'Api-Key': PINECONE_KEY },
  });
  if (!fetchResp.ok) { errors.push(`fetch ${fetchResp.status}`); break; }
  const fetchData = await fetchResp.json();
  const vectors = fetchData.vectors || {};

  // Transform to VectorItem shape
  const items = Object.entries(vectors).map(([id, vec]) => {
    const meta = vec.metadata || {};
    const docId = meta.document_id || meta.source || id.split('_chunk_')[0];
    const text = stripNull(meta.text || meta.chunk_text || '(no text)');
    const enriched = {};
    for (const [k, v] of Object.entries(meta)) enriched[k] = stripNull(v);
    enriched.document_id = docId;
    if (enriched.chunk_index === undefined) enriched.chunk_index = 0;
    return { id, content: text, embedding: vec.values, metadata: enriched };
  });

  // Upsert in sub-batches of UPSERT_CHUNK
  for (let i = 0; i < items.length; i += UPSERT_CHUNK) {
    const chunk = items.slice(i, i + UPSERT_CHUNK);
    const resp = await fetch(`${BACKEND}/api/internal/vector-upsert`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-gda-key': GDA_KEY },
      body: JSON.stringify({ collection, items: chunk }),
    });
    if (resp.ok) upserted += chunk.length;
    else errors.push(`upsert batch ${batchNum} chunk ${i}: ${resp.status}`);
  }
  fetched += ids.length;
  batchNum++;
} while (token);

return [{ json: { namespace: ns, collection, expected_count, fetched, upserted, batches: batchNum, errors, status: errors.length ? 'partial' : 'success' } }];

// Quick sanity check: query pgvector with a dummy vector to verify data is queryable.
const GDA_KEY = '{{ $env.GDA_WEBHOOK_KEY }}';
const BACKEND = 'http://gda-backend:3001';
const item = $input.first().json;
const embedding = new Array(1536).fill(0.01);
const resp = await fetch(`${BACKEND}/api/internal/vector-query`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-gda-key': GDA_KEY },
  body: JSON.stringify({ collection: item.collection, embedding, topK: 1 }),
});
const data = resp.ok ? await resp.json() : { error: await resp.text() };
return [{ json: { ...item, pgvector_check: resp.ok ? 'ok' : 'error', sample_id: data?.data?.results?.[0]?.id || 'none' } }];
